class Solution(object):
    def matrixSum(self, nums):
        for row in nums:
            row.sort(reverse=True)
        score = 0
        for col in range(len(nums[0])):
            col_max = max(nums[row][col] for row in range(len(nums)))
            score += col_max
        return score
